 56	// What to do when an error happens (e.g., a push or pull fails)
 57	static inline void on_error()
 58	{
 59	  // show the call stack
 60	  int fd = STDERR_FILENO;
 61	  static const char msg[] = "---stack trace---\n";
 62	  __attribute__((unused)) int r = write(fd, msg, sizeof(msg) - 1);
 63	  void *buffer[100];
 64	  int nptrs = backtrace(buffer, sizeof(buffer) / sizeof(buffer[0]));
 65	  backtrace_symbols_fd(buffer, nptrs, fd);
 66	
 67	  // abort();
 68	}
