 73	{
 74	  uint8_t *pOut = *out;
 75	
 76	  if ((end - pOut) >= 1) {
 77	    pOut[0] = in;
 78	    (*out) += 1;
 79	    return 1;
 80	  } else {
 81	    NFAPI_TRACE(NFAPI_TRACE_ERROR, "%s no space in buffer\n", __FUNCTION__);
 82	    on_error();
 83	    return 0;
 84	  }
