uint8_t pull16(uint8_t **in, uint16_t *out, uint8_t *end)
{
  uint8_t *pIn = *in;

  if ((end - pIn) >= 2) {
#ifdef FAPI_BYTE_ORDERING_BIG_ENDIAN
    *out = ((pIn[1]) << 8) | pIn[0];
#else
    *out = ((pIn[0]) << 8) | pIn[1];
#endif
    (*in) += 2;
    return 2;
  } else {
    NFAPI_TRACE(NFAPI_TRACE_ERROR, "%s no space in buffer\n", __FUNCTION__);
    on_error();
    return 0;
  }
}

